            let preciseExpectedSubtotal = new Big(0);
            items.forEach(item => preciseExpectedSubtotal = preciseExpectedSubtotal.plus(new Big(item.price)));
            const preciseExpectedTax = preciseExpectedSubtotal.times(new Big(TAX_RATE));
            const preciseExpectedTotal = preciseExpectedSubtotal.plus(preciseExpectedTax);

            const comparisonDiv = document.getElementById('fixed-comparison');
            let comparisonMessage = `Is Grand Total ($${grandTotal.toFixed(2)}) === Expected Total ($${preciseExpectedTotal.toFixed(2)})? `;
            if (grandTotal.eq(preciseExpectedTotal)) { // Use Big.js's .eq() for equality
                comparisonDiv.classList.remove('fail');
                comparisonDiv.classList.add('pass');
                comparisonMessage += `<span style="color: green;">YES!</span>`;
            } else {
                comparisonDiv.classList.remove('pass');
                comparisonDiv.classList.add('fail');
                comparisonMessage += `<span style="color: red;">NO! (This should not happen with Big.js if calculations are identical)</span>`;
            }
            comparisonDiv.innerHTML = comparisonMessage + `<br><em>Big.js values: Grand Total = ${grandTotal.toString()}, Expected = ${preciseExpectedTotal.toString()}</em>`;
        }

        // Run calculations on page load
        document.addEventListener('DOMContentLoaded', () => {
            calculateBrokenCart();
            calculateFixedCart();
        });
    </script>
</body>
</html>
